const workerFunction = require('./path/to/workerCode.js'); // 根据实际路径调整

const workerCode = workerFunction.toString();
const workerCodeToBlob = `(${workerCode})()`;

const blob = new Blob([workerCodeToBlob], { type: "application/javascript" });
const workerUrl = URL.createObjectURL(blob);
const worker = new Worker(workerUrl);

const largeData = Array.from({ length: 500000 }, () => ({ aa: 111, bb: 'test', cc: 'tesate' }));

const chunkSize = 1000;
const totalChunks = Math.ceil(largeData.length / chunkSize);

async function sendChunks() {
    for (let i = 0; i < totalChunks; i++) {
        const start = i * chunkSize;
        const end = Math.min(largeData.length, start + chunkSize);
        const chunk = largeData.slice(start, end);
        const jsonString = JSON.stringify(chunk);
        const arrayBuffer = stringToArrayBuffer(jsonString);

        worker.postMessage({ type: 'initial', buffer: arrayBuffer, index: i, total: totalChunks }, [arrayBuffer]);

        await new Promise(resolve => setTimeout(resolve, 10));
    }
}

worker.onmessage = function(event) {
    if (event.data.type === 'result') {
        receivedBufferFromWorker(event.data.buffer, event.data.index, event.data.total);
    }
};

sendChunks();

let receivedBuffersFromWorker = [];
function receivedBufferFromWorker(buffer, index, total) {
    receivedBuffersFromWorker[index] = buffer;

    if (receivedBuffersFromWorker.filter(Boolean).length === total) {
        const completeBuffer = new Uint8Array(receivedBuffersFromWorker.reduce((acc, buf) => acc + buf.byteLength, 0));
        let offset = 0;
        for (let buf of receivedBuffersFromWorker) {
            completeBuffer.set(new Uint8Array(buf), offset);
            offset += buf.byteLength;
        }

        const decoder = new TextDecoder();
        const jsonString = decoder.decode(completeBuffer);

        const completeData = JSON.parse(jsonString);
        console.log('Received complete worker data:', completeData);
    }
}

function stringToArrayBuffer(str) {
    const encoder = new TextEncoder();
    return encoder.encode(str).buffer;
}
